namespace sv_16d8eb073f7343ee977935e427b39d18.Services;

public record UserProfile(string DisplayName, string Email, string AvatarUrl, string Bio);

public record NotificationPrefs(
    bool EmailNotifications,
    bool PushNotifications,
    bool WeeklyDigest,
    List<string> MutedChannels);

public record SecuritySettings(
    bool TwoFactorEnabled,
    DateTime? LastPasswordChange,
    List<ActiveSession> Sessions);

public record ActiveSession(string Id, string Device, string Location, DateTime LastActive);

public record AppearanceSettings(string Theme, string FontSize, string Language, bool CompactMode);

public interface ISettingsService
{
    Task<UserProfile> GetProfileAsync();
    Task SaveProfileAsync(UserProfile profile);
    Task<NotificationPrefs> GetNotificationPrefsAsync();
    Task SaveNotificationPrefsAsync(NotificationPrefs prefs);
    Task<SecuritySettings> GetSecuritySettingsAsync();
    Task ChangePasswordAsync(string currentPassword, string newPassword);
    Task RevokeSessionAsync(string sessionId);
    Task<AppearanceSettings> GetAppearanceAsync();
    Task SaveAppearanceAsync(AppearanceSettings settings);
}

@if (Visible)
{
    <div class="modal d-block" tabindex="-1" style="background-color: rgba(0,0,0,0.5);">
        <div class="modal-dialog modal-dialog-centered">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Revoke Session</h5>
                    <button type="button" class="btn-close" @onclick="OnCancel"></button>
                </div>
                <div class="modal-body">
                    @if (Session is not null)
                    {
                        <p>
                            Are you sure you want to revoke the session on
                            <strong>@Session.Device</strong> in <strong>@Session.Location</strong>?
                        </p>
                        <p class="text-muted mb-0">
                            Last active: @Session.LastActive.ToString("g")
                        </p>
                    }
                </div>
                <div class="modal-footer">
                    <button class="btn btn-outline-secondary" @onclick="OnCancel">Cancel</button>
                    <button class="btn btn-danger" @onclick="OnConfirm">Revoke</button>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public bool Visible { get; set; }
    [Parameter] public ActiveSession? Session { get; set; }
    [Parameter] public EventCallback OnConfirm { get; set; }
    [Parameter] public EventCallback OnCancel { get; set; }
}

@inject ISettingsService SettingsService

<div class="card mb-4">
    <div class="card-header d-flex justify-content-between align-items-center"
         role="button" @onclick="() => isExpanded = !isExpanded">
        <span>🔑 Change Password</span>
        <span>@(isExpanded ? "▲" : "▼")</span>
    </div>

    @if (isExpanded)
    {
        <div class="card-body">
            @if (!string.IsNullOrEmpty(message))
            {
                <div class="alert @(isError ? "alert-danger" : "alert-success") alert-dismissible">
                    @message
                    <button type="button" class="btn-close" @onclick="() => message = null"></button>
                </div>
            }

            <div class="mb-3">
                <label class="form-label">Current Password</label>
                <input type="password" class="form-control" @bind="currentPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">New Password</label>
                <input type="password" class="form-control" @bind="newPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">Confirm New Password</label>
                <input type="password" class="form-control" @bind="confirmPassword" />
            </div>
            <button class="btn btn-primary" @onclick="UpdatePasswordAsync" disabled="@isSubmitting">
                @(isSubmitting ? "Updating..." : "Update Password")
            </button>
        </div>
    }
</div>

@code {
    private bool isExpanded;
    private string currentPassword = "";
    private string newPassword = "";
    private string confirmPassword = "";
    private string? message;
    private bool isError;
    private bool isSubmitting;

    private async Task UpdatePasswordAsync()
    {
        message = null;

        if (string.IsNullOrWhiteSpace(currentPassword)
            || string.IsNullOrWhiteSpace(newPassword))
        {
            message = "All password fields are required.";
            isError = true;
            return;
        }

        if (newPassword != confirmPassword)
        {
            message = "New password and confirmation do not match.";
            isError = true;
            return;
        }

        isSubmitting = true;
        try
        {
            await SettingsService.ChangePasswordAsync(currentPassword, newPassword);
            message = "Password updated successfully!";
            isError = false;
            currentPassword = "";
            newPassword = "";
            confirmPassword = "";
        }
        catch (Exception ex)
        {
            message = $"Failed to update password: {ex.Message}";
            isError = true;
        }
        finally
        {
            isSubmitting = false;
        }
    }
}

