@inject ISettingsService SettingsService

<h3 class="mb-4">Profile Settings</h3>

@if (isLoading)
{
    <div class="d-flex align-items-center gap-2">
        <div class="spinner-border spinner-border-sm"></div>
        <span>Loading profile…</span>
    </div>
}
else
{
    @if (!string.IsNullOrEmpty(message))
    {
        <div class="alert @(isError ? "alert-danger" : "alert-success") alert-dismissible fade show">
            @message
            <button type="button" class="btn-close" @onclick="() => message = null"></button>
        </div>
    }

    <div class="mb-4">
        <div class="d-flex align-items-center gap-3 mb-2">
            @if (!string.IsNullOrEmpty(avatarUrl))
            {
                <img src="@avatarUrl" alt="Avatar"
                     class="rounded-circle border"
                     style="width:80px;height:80px;object-fit:cover;" />
            }
            else
            {
                <div class="rounded-circle bg-secondary d-flex align-items-center justify-content-center"
                     style="width:80px;height:80px;">
                    <span class="text-white fs-3">👤</span>
                </div>
            }
            <div class="flex-grow-1">
                <label class="form-label mb-1">Avatar URL</label>
                <input class="form-control" @bind="avatarUrl" placeholder="https://example.com/avatar.png" />
            </div>
        </div>
    </div>

    <div class="mb-3">
        <label class="form-label">Display Name</label>
        <input class="form-control" @bind="displayName" />
    </div>

    <div class="mb-3">
        <label class="form-label">Email</label>
        <input type="email" class="form-control" @bind="email" />
    </div>

    <div class="mb-3">
        <label class="form-label">Bio</label>
        <textarea class="form-control" rows="4" @bind="bio" placeholder="Tell us about yourself…"></textarea>
    </div>

    <div class="d-flex gap-2">
        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@isSaving">
            @(isSaving ? "Saving…" : "Save Changes")
        </button>
        <button class="btn btn-outline-secondary" @onclick="Discard">
            Discard Changes
        </button>
    </div>
}

@code {
    private string displayName = "";
    private string email = "";
    private string avatarUrl = "";
    private string bio = "";

    private UserProfile? savedProfile;
    private bool isLoading = true;
    private bool isSaving;
    private string? message;
    private bool isError;

    protected override async Task OnInitializedAsync()
    {
        savedProfile = await SettingsService.GetProfileAsync();
        ApplyProfile(savedProfile);
        isLoading = false;
    }

    private void ApplyProfile(UserProfile profile)
    {
        displayName = profile.DisplayName;
        email = profile.Email;
        avatarUrl = profile.AvatarUrl;
        bio = profile.Bio;
    }

    private async Task SaveAsync()
    {
        isSaving = true;
        try
        {
            var profile = new UserProfile(displayName, email, avatarUrl, bio);
            await SettingsService.SaveProfileAsync(profile);
            savedProfile = profile;
            message = "Profile saved successfully!";
            isError = false;
        }
        catch (Exception ex)
        {
            message = $"Failed to save: {ex.Message}";
            isError = true;
        }
        finally
        {
            isSaving = false;
        }
    }

    private void Discard()
    {
        if (savedProfile is not null)
        {
            ApplyProfile(savedProfile);
            message = null;
        }
    }
}

@inject ISettingsService SettingsService

<h3 class="mb-4">Notification Preferences</h3>

@if (isLoading)
{
    <div class="d-flex align-items-center gap-2">
        <div class="spinner-border spinner-border-sm"></div>
        <span>Loading preferences…</span>
    </div>
}
else
{
    @if (!string.IsNullOrEmpty(message))
    {
        <div class="alert @(isError ? "alert-danger" : "alert-success") alert-dismissible fade show">
            @message
            <button type="button" class="btn-close" @onclick="() => message = null"></button>
        </div>
    }

    <div class="card mb-4">
        <div class="card-body">
            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" role="switch"
                       id="emailNotif" @bind="emailNotifications" />
                <label class="form-check-label" for="emailNotif">
                    Email Notifications
                </label>
                <div class="form-text">Receive notifications via email</div>
            </div>

            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" role="switch"
                       id="pushNotif" @bind="pushNotifications" />
                <label class="form-check-label" for="pushNotif">
                    Push Notifications
                </label>
                <div class="form-text">Receive push notifications in your browser</div>
            </div>

            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" role="switch"
                       id="weeklyDigest" @bind="weeklyDigest" />
                <label class="form-check-label" for="weeklyDigest">
                    Weekly Digest
                </label>
                <div class="form-text">Get a weekly summary of activity</div>
            </div>
        </div>
    </div>

    <div class="card mb-4">
        <div class="card-header">Muted Channels</div>
        <div class="card-body">
            @foreach (var channel in allChannels)
            {
                var isMuted = mutedChannels.Contains(channel);
                <div class="form-check mb-2">
                    <input class="form-check-input" type="checkbox" checked="@isMuted"
                           id="@($"ch-{channel}")"
                           @onchange="e => ToggleChannel(channel, (bool)(e.Value ?? false))" />
                    <label class="form-check-label" for="@($"ch-{channel}")">
                        @channel
                    </label>
                </div>
            }
        </div>
    </div>

    <button class="btn btn-primary" @onclick="SaveAsync" disabled="@isSaving">
        @(isSaving ? "Saving…" : "Save Preferences")
    </button>
}

@code {
    private static readonly string[] allChannels =
        ["General", "Announcements", "Engineering", "Design", "Marketing", "Support"];

    private bool emailNotifications;
    private bool pushNotifications;
    private bool weeklyDigest;
    private HashSet<string> mutedChannels = new();

    private bool isLoading = true;
    private bool isSaving;
    private string? message;
    private bool isError;

    protected override async Task OnInitializedAsync()
    {
        var prefs = await SettingsService.GetNotificationPrefsAsync();
        emailNotifications = prefs.EmailNotifications;
        pushNotifications = prefs.PushNotifications;
        weeklyDigest = prefs.WeeklyDigest;
        mutedChannels = new HashSet<string>(prefs.MutedChannels);
        isLoading = false;
    }

    private void ToggleChannel(string channel, bool muted)
    {
        if (muted)
            mutedChannels.Add(channel);
        else
            mutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        isSaving = true;
        try
        {
            var prefs = new NotificationPrefs(
                emailNotifications,
                pushNotifications,
                weeklyDigest,
                mutedChannels.ToList());
            await SettingsService.SaveNotificationPrefsAsync(prefs);
            message = "Preferences saved successfully!";
            isError = false;
        }
        catch (Exception ex)
        {
            message = $"Failed to save: {ex.Message}";
            isError = true;
        }
        finally
        {
            isSaving = false;
        }
    }
}

@inject ISettingsService SettingsService

<h3 class="mb-4">Security Settings</h3>

@if (isLoading)
{
    <div class="d-flex align-items-center gap-2">
        <div class="spinner-border spinner-border-sm"></div>
        <span>Loading security settings…</span>
    </div>
}
else
{
    @if (!string.IsNullOrEmpty(message))
    {
        <div class="alert @(isError ? "alert-danger" : "alert-success") alert-dismissible fade show">
            @message
            <button type="button" class="btn-close" @onclick="() => message = null"></button>
        </div>
    }

    <ChangePasswordPanel />

    <div class="card mb-4">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center">
                <div>
                    <h6 class="mb-1">Two-Factor Authentication</h6>
                    <span class="badge @(twoFactorEnabled ? "bg-success" : "bg-secondary")">
                        @(twoFactorEnabled ? "Enabled" : "Disabled")
                    </span>
                    @if (lastPasswordChange.HasValue)
                    {
                        <div class="form-text mt-1">
                            Last password change: @lastPasswordChange.Value.ToString("MMMM d, yyyy")
                        </div>
                    }
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch"
                           id="twoFactor" @bind="twoFactorEnabled" />
                </div>
            </div>
        </div>
    </div>

    <div class="card mb-4">
        <div class="card-header">Active Sessions</div>
        <div class="card-body p-0">
            <div class="table-responsive">
                <table class="table table-hover mb-0">
                    <thead>
                        <tr>
                            <th>Device</th>
                            <th>Location</th>
                            <th>Last Active</th>
                            <th class="text-end">Action</th>
                        </tr>
                    </thead>
                    <tbody>
                        @foreach (var session in sessions)
                        {
                            var isCurrent = session == sessions.FirstOrDefault();
                            <tr>
                                <td>
                                    @session.Device
                                    @if (isCurrent)
                                    {
                                        <span class="badge bg-primary ms-1">Current</span>
                                    }
                                </td>
                                <td>@session.Location</td>
                                <td>@session.LastActive.ToString("g")</td>
                                <td class="text-end">
                                    @if (!isCurrent)
                                    {
                                        <button class="btn btn-sm btn-outline-danger"
                                                @onclick="() => ShowRevokeDialog(session)">
                                            Revoke
                                        </button>
                                    }
                                </td>
                            </tr>
                        }
                    </tbody>
                </table>
            </div>
        </div>
    </div>
}

<RevokeSessionDialog Visible="@showRevokeDialog"
                     Session="@sessionToRevoke"
                     OnConfirm="ConfirmRevokeAsync"
                     OnCancel="() => showRevokeDialog = false" />

@code {
    private bool twoFactorEnabled;
    private DateTime? lastPasswordChange;
    private List<ActiveSession> sessions = new();

    private bool isLoading = true;
    private string? message;
    private bool isError;

    private bool showRevokeDialog;
    private ActiveSession? sessionToRevoke;

    protected override async Task OnInitializedAsync()
    {
        await LoadAsync();
    }

    private async Task LoadAsync()
    {
        isLoading = true;
        var settings = await SettingsService.GetSecuritySettingsAsync();
        twoFactorEnabled = settings.TwoFactorEnabled;
        lastPasswordChange = settings.LastPasswordChange;
        sessions = settings.Sessions;
        isLoading = false;
    }

    private void ShowRevokeDialog(ActiveSession session)
    {
        sessionToRevoke = session;
        showRevokeDialog = true;
    }

    private async Task ConfirmRevokeAsync()
    {
        if (sessionToRevoke is null) return;

        showRevokeDialog = false;
        try
        {
            await SettingsService.RevokeSessionAsync(sessionToRevoke.Id);
            sessions.Remove(sessionToRevoke);
            message = $"Session on {sessionToRevoke.Device} has been revoked.";
            isError = false;
        }
        catch (Exception ex)
        {
            message = $"Failed to revoke session: {ex.Message}";
            isError = true;
        }
        finally
        {
            sessionToRevoke = null;
        }
    }
}

@inject ISettingsService SettingsService

<h3 class="mb-4">Appearance</h3>

@if (isLoading)
{
    <div class="d-flex align-items-center gap-2">
        <div class="spinner-border spinner-border-sm"></div>
        <span>Loading appearance settings…</span>
    </div>
}
else
{
    @if (!string.IsNullOrEmpty(message))
    {
        <div class="alert @(isError ? "alert-danger" : "alert-success") alert-dismissible fade show">
            @message
            <button type="button" class="btn-close" @onclick="() => message = null"></button>
        </div>
    }

    <div class="row">
        <div class="col-md-6">
            <div class="card mb-4">
                <div class="card-header">Theme</div>
                <div class="card-body">
                    @foreach (var t in themes)
                    {
                        <div class="form-check mb-2">
                            <input class="form-check-input" type="radio" name="theme"
                                   id="@($"theme-{t}")" value="@t"
                                   checked="@(theme == t)"
                                   @onchange="() => theme = t" />
                            <label class="form-check-label" for="@($"theme-{t}")">@t</label>
                        </div>
                    }
                </div>
            </div>

            <div class="card mb-4">
                <div class="card-header">Font Size</div>
                <div class="card-body">
                    @foreach (var fs in fontSizes)
                    {
                        <div class="form-check form-check-inline">
                            <input class="form-check-input" type="radio" name="fontSize"
                                   id="@($"fs-{fs}")" value="@fs"
                                   checked="@(fontSize == fs)"
                                   @onchange="() => fontSize = fs" />
                            <label class="form-check-label" for="@($"fs-{fs}")">@fs</label>
                        </div>
                    }
                </div>
            </div>

            <div class="card mb-4">
                <div class="card-header">Language</div>
                <div class="card-body">
                    <select class="form-select" @bind="language">
                        @foreach (var lang in languages)
                        {
                            <option value="@lang">@lang</option>
                        }
                    </select>
                </div>
            </div>

            <div class="card mb-4">
                <div class="card-body">
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" role="switch"
                               id="compactMode" @bind="compactMode" />
                        <label class="form-check-label" for="compactMode">Compact Mode</label>
                        <div class="form-text">Reduce spacing and padding throughout the UI</div>
                    </div>
                </div>
            </div>

            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@isSaving">
                @(isSaving ? "Saving…" : "Save")
            </button>
        </div>

        <div class="col-md-6">
            <h6 class="mb-3">Live Preview</h6>
            <AppearancePreview Settings="@CurrentSettings" />
        </div>
    </div>
}

@code {
    private static readonly string[] themes = ["Light", "Dark", "System"];
    private static readonly string[] fontSizes = ["Small", "Medium", "Large"];
    private static readonly string[] languages =
        ["English", "Spanish", "French", "German", "Japanese", "Chinese", "Portuguese"];

