            </div>

            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" role="switch"
                       id="weeklyDigest" @bind="weeklyDigest" />
                <label class="form-check-label" for="weeklyDigest">
                    Weekly Digest
                </label>
                <div class="form-text">Get a weekly summary of activity</div>
            </div>
        </div>
    </div>

    <div class="card mb-4">
        <div class="card-header">Muted Channels</div>
        <div class="card-body">
            @foreach (var channel in allChannels)
            {
                var isMuted = mutedChannels.Contains(channel);
                <div class="form-check mb-2">
                    <input class="form-check-input" type="checkbox" checked="@isMuted"
                           id="@($"ch-{channel}")"
                           @onchange="e => ToggleChannel(channel, (bool)(e.Value ?? false))" />
                    <label class="form-check-label" for="@($"ch-{channel}")">
                        @channel
                    </label>
                </div>
            }
        </div>
    </div>

