                <div>
                    <h6 class="mb-1">Two-Factor Authentication</h6>
                    <span class="badge @(twoFactorEnabled ? "bg-success" : "bg-secondary")">
                        @(twoFactorEnabled ? "Enabled" : "Disabled")
                    </span>
                    @if (lastPasswordChange.HasValue)
                    {
                        <div class="form-text mt-1">
                            Last password change: @lastPasswordChange.Value.ToString("MMMM d, yyyy")
                        </div>
                    }
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch"
                           id="twoFactor" @bind="twoFactorEnabled" />
                </div>
            </div>
        </div>
    </div>

    <div class="card mb-4">
        <div class="card-header">Active Sessions</div>
        <div class="card-body p-0">
            <div class="table-responsive">
                <table class="table table-hover mb-0">
                    <thead>
                        <tr>
                            <th>Device</th>
                            <th>Location</th>
                            <th>Last Active</th>
                            <th class="text-end">Action</th>
                        </tr>
                    </thead>
                    <tbody>
                        @foreach (var session in sessions)
                        {
                            var isCurrent = session == sessions.FirstOrDefault();
                            <tr>
                                <td>
                                    @session.Device
                                    @if (isCurrent)
                                    {
                                        <span class="badge bg-primary ms-1">Current</span>
                                    }
                                </td>
                                <td>@session.Location</td>
                                <td>@session.LastActive.ToString("g")</td>
                                <td class="text-end">
                                    @if (!isCurrent)
                                    {
                                        <button class="btn btn-sm btn-outline-danger"
                                                @onclick="() => ShowRevokeDialog(session)">
                                            Revoke
                                        </button>
                                    }
                                </td>
                            </tr>
                        }
                    </tbody>
                </table>
            </div>
        </div>
    </div>
}

<RevokeSessionDialog Visible="@showRevokeDialog"
                     Session="@sessionToRevoke"
                     OnConfirm="ConfirmRevokeAsync"
                     OnCancel="() => showRevokeDialog = false" />

@code {
    private bool twoFactorEnabled;
    private DateTime? lastPasswordChange;
    private List<ActiveSession> sessions = new();

    private bool isLoading = true;
    private string? message;
    private bool isError;

    private bool showRevokeDialog;
    private ActiveSession? sessionToRevoke;

    protected override async Task OnInitializedAsync()
    {
        await LoadAsync();
    }

    private async Task LoadAsync()
    {
        isLoading = true;
        var settings = await SettingsService.GetSecuritySettingsAsync();
        twoFactorEnabled = settings.TwoFactorEnabled;
        lastPasswordChange = settings.LastPasswordChange;
        sessions = settings.Sessions;
        isLoading = false;
    }

    private void ShowRevokeDialog(ActiveSession session)
    {
        sessionToRevoke = session;
        showRevokeDialog = true;
    }

    private async Task ConfirmRevokeAsync()
    {
        if (sessionToRevoke is null) return;

        showRevokeDialog = false;
        try
        {
            await SettingsService.RevokeSessionAsync(sessionToRevoke.Id);
            sessions.Remove(sessionToRevoke);
            message = $"Session on {sessionToRevoke.Device} has been revoked.";
            isError = false;
        }
        catch (Exception ex)
        {
            message = $"Failed to revoke session: {ex.Message}";
            isError = true;
        }
        finally
        {
            sessionToRevoke = null;
        }
    }
}
