toolArgs.file_text:
@inject ISettingsService SettingsService

<h3 class="mb-4">Notification Preferences</h3>

@if (isLoading)
{
    <div class="d-flex align-items-center gap-2">
        <div class="spinner-border spinner-border-sm"></div>
        <span>Loading preferences…</span>
    </div>
}
else
{
    @if (!string.IsNullOrEmpty(message))
    {
        <div class="alert @(isError ? "alert-danger" : "alert-success") alert-dismissible fade show">
            @message
            <button type="button" class="btn-close" @onclick="() => message = null"></button>
        </div>
    }

    <div class="card mb-4">
        <div class="card-body">
            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" role="switch"
                       id="emailNotif" @bind="emailNotifications" />
                <label class="form-check-label" for="emailNotif">
                    Email Notifications
                </label>
                <div class="form-text">Receive notifications via email</div>
            </div>

            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" role="switch"
                       id="pushNotif" @bind="pushNotifications" />
                <label class="form-check-label" for="pushNotif">
                    Push Notifications
                </label>
                <div class="form-text">Receive push notifications in your browser</div>
            </div>

            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" role="switch"
                       id="weeklyDigest" @bind="weeklyDigest" />
                <label class="form-check-label" for="weeklyDigest">
                    Weekly Digest
                </label>
                <div class="form-text">Get a weekly summary of activity</div>
            </div>
        </div>
    </div>

    <div class="card mb-4">
        <div class="card-header">Muted Channels</div>
        <div class="card-body">
            @foreach (var channel in allChannels)
            {
                var isMuted = mutedChannels.Contains(channel);
                <div class="form-check mb-2">
                    <input class="form-check-input" type="checkbox" checked="@isMuted"
                           id="@($"ch-{channel}")"
                           @onchange="e => ToggleChannel(channel, (bool)(e.Value ?? false))" />
                    <label class="form-check-label" for="@($"ch-{channel}")">
                        @channel
                    </label>
                </div>
            }
        </div>
    </div>

    <button class="btn btn-primary" @onclick="SaveAsync" disabled="@isSaving">
        @(isSaving ? "Saving…" : "Save Preferences")
    </button>
}

@code {
    private static readonly string[] allChannels =
        ["General", "Announcements", "Engineering", "Design", "Marketing", "Support"];

    private bool emailNotifications;
    private bool pushNotifications;
    private bool weeklyDigest;
    private HashSet<string> mutedChannels = new();

    private bool isLoading = true;
    private bool isSaving;
    private string? message;
    private bool isError;

    protected override async Task OnInitializedAsync()
    {
        var prefs = await SettingsService.GetNotificationPrefsAsync();
        emailNotifications = prefs.EmailNotifications;
        pushNotifications = prefs.PushNotifications;
        weeklyDigest = prefs.WeeklyDigest;
        mutedChannels = new HashSet<string>(prefs.MutedChannels);
        isLoading = false;
    }

    private void ToggleChannel(string channel, bool muted)
    {
        if (muted)
            mutedChannels.Add(channel);
        else
            mutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        isSaving = true;
        try
        {
            var prefs = new NotificationPrefs(
                emailNotifications,
                pushNotifications,
                weeklyDigest,
                mutedChannels.ToList());
            await SettingsService.SaveNotificationPrefsAsync(prefs);
            message = "Preferences saved successfully!";
            isError = false;
        }
        catch (Exception ex)
        {
            message = $"Failed to save: {ex.Message}";
            isError = true;
        }
        finally
        {
            isSaving = false;
        }
    }
}

