toolArgs.file_text:
@inject ISettingsService SettingsService

<h3 class="mb-4">Appearance</h3>

@if (isLoading)
{
    <div class="d-flex align-items-center gap-2">
        <div class="spinner-border spinner-border-sm"></div>
        <span>Loading appearance settings…</span>
    </div>
}
else
{
    @if (!string.IsNullOrEmpty(message))
    {
        <div class="alert @(isError ? "alert-danger" : "alert-success") alert-dismissible fade show">
            @message
            <button type="button" class="btn-close" @onclick="() => message = null"></button>
        </div>
    }

    <div class="row">
        <div class="col-md-6">
            <div class="card mb-4">
                <div class="card-header">Theme</div>
                <div class="card-body">
                    @foreach (var t in themes)
                    {
                        <div class="form-check mb-2">
                            <input class="form-check-input" type="radio" name="theme"
                                   id="@($"theme-{t}")" value="@t"
                                   checked="@(theme == t)"
                                   @onchange="() => theme = t" />
                            <label class="form-check-label" for="@($"theme-{t}")">@t</label>
                        </div>
                    }
                </div>
            </div>

            <div class="card mb-4">
                <div class="card-header">Font Size</div>
                <div class="card-body">
                    @foreach (var fs in fontSizes)
                    {
                        <div class="form-check form-check-inline">
                            <input class="form-check-input" type="radio" name="fontSize"
                                   id="@($"fs-{fs}")" value="@fs"
                                   checked="@(fontSize == fs)"
                                   @onchange="() => fontSize = fs" />
                            <label class="form-check-label" for="@($"fs-{fs}")">@fs</label>
                        </div>
                    }
                </div>
            </div>

            <div class="card mb-4">
                <div class="card-header">Language</div>
                <div class="card-body">
                    <select class="form-select" @bind="language">
                        @foreach (var lang in languages)
                        {
                            <option value="@lang">@lang</option>
                        }
                    </select>
                </div>
            </div>

            <div class="card mb-4">
                <div class="card-body">
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" role="switch"
                               id="compactMode" @bind="compactMode" />
                        <label class="form-check-label" for="compactMode">Compact Mode</label>
                        <div class="form-text">Reduce spacing and padding throughout the UI</div>
                    </div>
                </div>
            </div>

            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@isSaving">
                @(isSaving ? "Saving…" : "Save")
            </button>
        </div>

        <div class="col-md-6">
            <h6 class="mb-3">Live Preview</h6>
            <AppearancePreview Settings="@CurrentSettings" />
        </div>
    </div>
}

@code {
    private static readonly string[] themes = ["Light", "Dark", "System"];
    private static readonly string[] fontSizes = ["Small", "Medium", "Large"];
    private static readonly string[] languages =
        ["English", "Spanish", "French", "German", "Japanese", "Chinese", "Portuguese"];

    private string theme = "Light";
    private string fontSize = "Medium";
    private string language = "English";
    private bool compactMode;

    private bool isLoading = true;
    private bool isSaving;
    private string? message;
    private bool isError;

    private AppearanceSettings CurrentSettings =>
        new(theme, fontSize, language, compactMode);

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetAppearanceAsync();
        theme = settings.Theme;
        fontSize = settings.FontSize;
        language = settings.Language;
        compactMode = settings.CompactMode;
        isLoading = false;
    }

    private async Task SaveAsync()
    {
        isSaving = true;
        try
        {
            await SettingsService.SaveAppearanceAsync(CurrentSettings);
            message = "Appearance settings saved!";
            isError = false;
        }
        catch (Exception ex)
        {
            message = $"Failed to save: {ex.Message}";
            isError = true;
        }
        finally
        {
            isSaving = false;
        }
    }
}

